import React, { useState, useEffect, useCallback } from "react";
import { useDocuments } from "../../hooks/useDocuments";
import type { Document } from "../Documents/document";
import PDFViewer from './PDFViewer';
import AudioPlayer from './AudioPlayer';
import TranscriptionEditor from './TranscriptionEditor';

const Transcription: React.FC = () => {
  const { documents, loading, error, updateDocumentWithVersioning } = useDocuments();
  
  // 🔑 AJOUT : État pour les sous-onglets
  const [activeSubTab, setActiveSubTab] = useState<'launch' | 'review' | 'tagging'>('launch');
  
  const [selectedDocument, setSelectedDocument] = useState<Document | null>(null);
  const [layoutMode, setLayoutMode] = useState<"horizontal" | "vertical" | "focus">("horizontal");
  const [splitRatio, setSplitRatio] = useState(0.5);
  const [transcriptionContent, setTranscriptionContent] = useState("");
  const [lastSaveTime, setLastSaveTime] = useState<Date | null>(null);
  const [startTime, setStartTime] = useState<Date>(new Date());

  // 🔑 MODIFICATION : Filtrer selon l'onglet actif
  const filteredDocuments = documents.filter(doc => {
    if (activeSubTab === 'launch') {
      // Documents à transcrire
      return doc.status === "imported" || doc.status === "transcribing";
    } else if (activeSubTab === 'review') {
      // Documents avec transcription composée (non vide)
      return (doc.status === "transcribed" || doc.status === "reviewing") && doc.content?.trim();
    } else {
      // Documents prêts pour le tagging
      return doc.status === "reviewed" || doc.status === "tagging";
    }
  });

  // Charger le contenu existant si document déjà en cours
  useEffect(() => {
    if (selectedDocument) {
      setTranscriptionContent(selectedDocument.content || "");
      setStartTime(new Date());
    }
  }, [selectedDocument]);

  // Déterminer le type de média
  const getMediaType = (fileUrl?: string | null): "audio" | "pdf" | "image" | "unknown" => {
    if (!fileUrl) return "unknown";
    const lowerUrl = fileUrl.toLowerCase();
    if (lowerUrl.match(/\.(mp3|wav|ogg|aac|m4a)$/)) return "audio";
    if (lowerUrl.endsWith(".pdf")) return "pdf";
    if (lowerUrl.match(/\.(jpg|jpeg|png|gif|bmp|webp)$/)) return "image";
    return "unknown";
  };

  const mediaType = selectedDocument ? getMediaType(selectedDocument.file_url) : "unknown";

  // Sauvegarde auto toutes les 30 secondes
  useEffect(() => {
    if (!selectedDocument) return;
    
    const interval = setInterval(() => {
      if (transcriptionContent.trim()) {
        localStorage.setItem(
          `bcm_transcription_${selectedDocument.id}`,
          JSON.stringify({
            content: transcriptionContent,
            timestamp: new Date().toISOString()
          })
        );
        setLastSaveTime(new Date());
      }
    }, 30000);
    
    return () => clearInterval(interval);
  }, [selectedDocument, transcriptionContent]);

  // Restaurer le brouillon au montage
  useEffect(() => {
    if (selectedDocument) {
      const draft = localStorage.getItem(`bcm_transcription_${selectedDocument.id}`);
      if (draft) {
        try {
          const { content } = JSON.parse(draft);
          if (content && !selectedDocument.content) {
            setTranscriptionContent(content);
          }
        } catch (err) {
          console.error('Erreur restauration brouillon:', err);
        }
      }
    }
  }, [selectedDocument]);

  // ✅ DÉPLACER handleSave AVANT l'effect qui l'utilise + useCallback
  const handleSave = useCallback(async () => {
    if (!selectedDocument) return;
    
    if (!transcriptionContent.trim()) {
      alert("⚠️ La transcription ne peut pas être vide");
      return;
    }
    
    try {
      // 🔑 AJOUT : Passage automatique au statut "transcribed" si contenu non vide
      const newStatus = transcriptionContent.trim() ? 'transcribed' : selectedDocument.status;
      
      await updateDocumentWithVersioning(selectedDocument.id, {
        ...selectedDocument,
        content: transcriptionContent,
        status: newStatus, // ✅ Seulement cette ligne ajoutée
        progress: 40,
      });
      
      // Nettoyer le brouillon
      localStorage.removeItem(`bcm_transcription_${selectedDocument.id}`);
      
      alert("✅ Transcription sauvegardée !\nLe document est maintenant prêt pour la relecture.");
      setSelectedDocument(null);
      setTranscriptionContent("");
    } catch (err) {
      console.error("Erreur sauvegarde:", err);
      alert("❌ Erreur lors de la sauvegarde");
    }
  }, [selectedDocument, transcriptionContent, updateDocumentWithVersioning]);

  // Raccourcis clavier
  useEffect(() => {
    if (!selectedDocument) return;

    const handleKeyDown = (e: KeyboardEvent) => {
      // ✅ Correction : Vérification type-safe de e.target
      if (e.code === 'Space' && e.target instanceof Element && !e.target.matches('input, textarea, [contenteditable]')) {
        e.preventDefault();
        const audio = document.querySelector('audio');
        if (audio) {
          if (audio.paused) audio.play();
          else audio.pause();
        }
      }
      
      // Ctrl + S = Sauvegarder
      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
        e.preventDefault();
        handleSave();
      }
      
      // Ctrl + ArrowLeft = Document précédent
      if ((e.ctrlKey || e.metaKey) && e.key === 'ArrowLeft') {
        e.preventDefault();
        const currentIndex = filteredDocuments.findIndex(d => d.id === selectedDocument.id);
        if (currentIndex > 0) {
          setSelectedDocument(filteredDocuments[currentIndex - 1]);
          setStartTime(new Date());
        }
      }
      
      // Ctrl + ArrowRight = Document suivant
      if ((e.ctrlKey || e.metaKey) && e.key === 'ArrowRight') {
        e.preventDefault();
        const currentIndex = filteredDocuments.findIndex(d => d.id === selectedDocument.id);
        if (currentIndex < filteredDocuments.length - 1) {
          setSelectedDocument(filteredDocuments[currentIndex + 1]);
          setStartTime(new Date());
        }
      }
      
      // Echap = Annuler / Retour
      if (e.key === 'Escape') {
        setSelectedDocument(null);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [selectedDocument, filteredDocuments, handleSave]);

  // Formatage du temps passé
  const formatTimeSpent = () => {
    const diff = Date.now() - startTime.getTime();
    const minutes = Math.floor(diff / 60000);
    const seconds = Math.floor((diff % 60000) / 1000);
    return `${minutes}m ${seconds.toString().padStart(2, '0')}s`;
  };

  // Temps écoulé depuis la dernière sauvegarde
  const getTimeAgo = (date: Date) => {
    const diff = Date.now() - date.getTime();
    const minutes = Math.floor(diff / 60000);
    if (minutes < 1) return 'quelques secondes';
    if (minutes < 60) return `${minutes} minute${minutes > 1 ? 's' : ''}`;
    const hours = Math.floor(minutes / 60);
    return `${hours} heure${hours > 1 ? 's' : ''}`;
  };

  // Document suivant
  const getNextDocument = () => {
    const currentIndex = filteredDocuments.findIndex(d => d.id === selectedDocument?.id);
    return currentIndex >= 0 && currentIndex < filteredDocuments.length - 1
      ? filteredDocuments[currentIndex + 1]
      : null;
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="max-w-3xl mx-auto bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-300 p-4 rounded-lg mb-6">
        <div className="flex items-center">
          <i className="fas fa-exclamation-triangle mr-3 text-xl"></i>
          <div>
            <h3 className="font-medium">Erreur</h3>
            <p>{error}</p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="container mx-auto px-4 py-6">
      <h1 className="text-2xl font-bold text-gray-900 dark:text-white mb-6 flex items-center">
        <i className="fas fa-microphone mr-3 text-blue-500"></i>
        Module de Transcription
      </h1>
      
      {/* 🔑 AJOUT : Sous-onglets */}
      <div className="mb-6">
        <div className="border-b border-gray-200 dark:border-gray-700">
          <nav className="-mb-px flex space-x-8">
            <button
              onClick={() => setActiveSubTab('launch')}
              className={`
                whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm
                ${activeSubTab === 'launch'
                  ? 'border-blue-500 text-blue-600 dark:text-blue-400'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300 dark:text-gray-400 dark:hover:text-gray-200'
                }
              `}
            >
              <i className="fas fa-rocket mr-2"></i>
              Lancement
              {activeSubTab !== 'launch' && filteredDocuments.length > 0 && (
                <span className="ml-2 inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300">
                  {filteredDocuments.length}
                </span>
              )}
            </button>
            
            <button
              onClick={() => setActiveSubTab('review')}
              className={`
                whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm
                ${activeSubTab === 'review'
                  ? 'border-green-500 text-green-600 dark:text-green-400'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300 dark:text-gray-400 dark:hover:text-gray-200'
                }
              `}
            >
              <i className="fas fa-eye mr-2"></i>
              Relecture
              {activeSubTab !== 'review' && (
                <span className="ml-2 inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-green-100 text-green-800 dark:bg-green-900/30 dark:text-green-300">
                  {documents.filter(d => (d.status === "transcribed" || d.status === "reviewing") && d.content?.trim()).length}
                </span>
              )}
            </button>
            
            <button
              onClick={() => setActiveSubTab('tagging')}
              className={`
                whitespace-nowrap py-4 px-1 border-b-2 font-medium text-sm
                ${activeSubTab === 'tagging'
                  ? 'border-purple-500 text-purple-600 dark:text-purple-400'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300 dark:text-gray-400 dark:hover:text-gray-200'
                }
              `}
            >
              <i className="fas fa-tags mr-2"></i>
              Tagging
              {activeSubTab !== 'tagging' && (
                <span className="ml-2 inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-300">
                  {documents.filter(d => d.status === "reviewed" || d.status === "tagging").length}
                </span>
              )}
            </button>
          </nav>
        </div>
      </div>
      
      {!selectedDocument ? (
        // === SÉLECTEUR DE DOCUMENT ===
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow">
          <div className="px-6 py-4 border-b border-gray-200 dark:border-gray-700">
            <h2 className="text-lg font-medium text-gray-800 dark:text-white">
              {activeSubTab === 'launch' && 'Documents à transcrire'}
              {activeSubTab === 'review' && 'Documents à relire'}
              {activeSubTab === 'tagging' && 'Documents à taguer'}
            </h2>
            <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
              {activeSubTab === 'launch' && 'Sélectionnez un document pour commencer la transcription'}
              {activeSubTab === 'review' && 'Sélectionnez un document avec transcription composée pour la relecture'}
              {activeSubTab === 'tagging' && 'Sélectionnez un document relu et validé pour ajouter des tags'}
            </p>
          </div>
          
          <div className="p-6">
            {filteredDocuments.length === 0 ? (
              <div className="text-center py-12">
                <div className="inline-block p-4 bg-gray-100 dark:bg-gray-700 rounded-full mb-4">
                  {activeSubTab === 'launch' && <i className="fas fa-microphone-alt text-4xl text-gray-400"></i>}
                  {activeSubTab === 'review' && <i className="fas fa-eye text-4xl text-gray-400"></i>}
                  {activeSubTab === 'tagging' && <i className="fas fa-tags text-4xl text-gray-400"></i>}
                </div>
                <h3 className="text-lg font-medium text-gray-800 dark:text-white mb-2">
                  {activeSubTab === 'launch' && 'Aucun document à transcrire'}
                  {activeSubTab === 'review' && 'Aucun document à relire'}
                  {activeSubTab === 'tagging' && 'Aucun document à taguer'}
                </h3>
                <p className="text-gray-500 dark:text-gray-400 mb-4">
                  {activeSubTab === 'launch' && 'Importez de nouveaux documents ou modifiez leur statut dans l\'onglet Documents'}
                  {activeSubTab === 'review' && 'Terminez la transcription des documents pour qu\'ils apparaissent ici'}
                  {activeSubTab === 'tagging' && 'Relisez et validez les documents pour qu\'ils apparaissent ici'}
                </p>
                <button
                  onClick={() => window.location.href = "/#documents"}
                  className="px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-md font-medium transition-colors"
                >
                  <i className="fas fa-arrow-left mr-2"></i>
                  Aller aux Documents
                </button>
              </div>
            ) : (
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                {filteredDocuments.map(doc => (
                  <div
                    key={doc.id}
                    className="border border-gray-200 dark:border-gray-700 rounded-lg p-5 hover:border-blue-400 hover:shadow-md transition-all cursor-pointer"
                    onClick={() => setSelectedDocument(doc)}
                  >
                    <div className="flex justify-between items-start">
                      <h3 className="font-bold text-gray-900 dark:text-white line-clamp-2">
                        {doc.title}
                      </h3>
                      <span className={`px-2.5 py-1 text-xs font-medium rounded-full ${
                        doc.status === "imported" 
                          ? "bg-yellow-100 text-yellow-800" 
                          : doc.status === "transcribing"
                          ? "bg-blue-100 text-blue-800"
                          : doc.status === "transcribed" || doc.status === "reviewing"
                          ? "bg-green-100 text-green-800"
                          : "bg-purple-100 text-purple-800"
                      }`}>
                        {doc.status === "imported" ? "À transcrire" : 
                         doc.status === "transcribing" ? "En cours" :
                         doc.status === "transcribed" ? "À relire" :
                         doc.status === "reviewing" ? "Relecture en cours" :
                         doc.status === "reviewed" ? "À taguer" :
                         "Tagging en cours"}
                      </span>
                    </div>
                    
                    <div className="mt-3 space-y-2">
                      <div className="flex items-center text-sm text-gray-600 dark:text-gray-400">
                        <i className="fas fa-file-alt mr-2 text-gray-400"></i>
                        <span>{doc.type}</span>
                      </div>
                      
                      {doc.file_url && (
                        <div className="flex items-center text-sm text-gray-600 dark:text-gray-400">
                          <i className={`fas ${
                            mediaType === "audio" ? "fa-headphones" :
                            mediaType === "pdf" ? "fa-file-pdf" :
                            mediaType === "image" ? "fa-image" : "fa-file"
                          } mr-2 text-gray-400`}></i>
                          <span>
                            {mediaType === "audio" ? "Fichier audio" :
                             mediaType === "pdf" ? "Document PDF" :
                             mediaType === "image" ? "Image" : "Fichier"}
                          </span>
                        </div>
                      )}
                      
                      <div className="flex items-center text-sm text-gray-600 dark:text-gray-400">
                        <i className="fas fa-user mr-2 text-gray-400"></i>
                        <span>{doc.assigned_to || "Non assigné"}</span>
                      </div>
                      
                      {/* 🔑 AJOUT : Statistiques pour l'onglet Relecture */}
                      {activeSubTab === 'review' && doc.content && (
                        <div className="flex items-center text-xs text-blue-600 dark:text-blue-400">
                          <i className="fas fa-font mr-1.5"></i>
                          <span>{doc.content.split(/\s+/).filter(w => w.length > 0).length} mots</span>
                        </div>
                      )}
                    </div>
                    
                    <div className="mt-4 pt-4 border-t border-gray-200 dark:border-gray-700">
                      <button
                        onClick={(e) => {
                          e.stopPropagation();
                          setSelectedDocument(doc);
                        }}
                        className="w-full px-4 py-2.5 bg-blue-600 hover:bg-blue-700 text-white rounded-md font-medium transition-colors flex items-center justify-center"
                      >
                        {activeSubTab === 'launch' && <><i className="fas fa-play mr-2"></i>Transcrire maintenant</>}
                        {activeSubTab === 'review' && <><i className="fas fa-eye mr-2"></i>Relire maintenant</>}
                        {activeSubTab === 'tagging' && <><i className="fas fa-tags mr-2"></i>Taguer maintenant</>}
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      ) : (
        // === INTERFACE DE TRANSCRIPTION AVEC AMÉLIORATIONS UX ===
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow overflow-hidden">
          {/* Header avec navigation rapide */}
          <div className="border-b border-gray-200 dark:border-gray-700 px-6 py-4 flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
            <div className="flex items-center gap-4 flex-wrap">
              <div>
                <h2 className="text-xl font-bold text-gray-900 dark:text-white">
                  <i className="fas fa-microphone mr-2 text-blue-500"></i>
                  {activeSubTab === 'launch' && 'Transcription'}
                  {activeSubTab === 'review' && 'Relecture'}
                  {activeSubTab === 'tagging' && 'Tagging'}
                  : {selectedDocument.title}
                </h2>
                <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">
                  {selectedDocument.source} • Assigné à : {selectedDocument.assigned_to}
                </p>
              </div>
              
              {/* Navigation rapide */}
              {filteredDocuments.length > 1 && (
                <div className="flex items-center gap-2 bg-gray-100 dark:bg-gray-700 px-3 py-1.5 rounded-lg">
                  <button
                    onClick={() => {
                      const currentIndex = filteredDocuments.findIndex(d => d.id === selectedDocument.id);
                      if (currentIndex > 0) {
                        setSelectedDocument(filteredDocuments[currentIndex - 1]);
                        setStartTime(new Date());
                      }
                    }}
                    disabled={filteredDocuments.findIndex(d => d.id === selectedDocument.id) === 0}
                    className="p-1.5 rounded-lg text-gray-600 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                    title="Document précédent (Ctrl+←)"
                  >
                    <i className="fas fa-arrow-left"></i>
                  </button>
                  
                  <span className="text-sm font-medium text-gray-700 dark:text-gray-300 px-2">
                    {filteredDocuments.findIndex(d => d.id === selectedDocument.id) + 1} / {filteredDocuments.length}
                  </span>
                  
                  <button
                    onClick={() => {
                      const currentIndex = filteredDocuments.findIndex(d => d.id === selectedDocument.id);
                      if (currentIndex < filteredDocuments.length - 1) {
                        setSelectedDocument(filteredDocuments[currentIndex + 1]);
                        setStartTime(new Date());
                      }
                    }}
                    disabled={filteredDocuments.findIndex(d => d.id === selectedDocument.id) === filteredDocuments.length - 1}
                    className="p-1.5 rounded-lg text-gray-600 dark:text-gray-400 hover:bg-gray-200 dark:hover:bg-gray-600 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                    title="Document suivant (Ctrl+→)"
                  >
                    <i className="fas fa-arrow-right"></i>
                  </button>
                </div>
              )}
            </div>
            
            <div className="flex flex-wrap gap-3">
              {/* Switch layout H/V/Focus */}
              <div className="flex items-center bg-gray-100 dark:bg-gray-700 rounded-md p-1">
                <button
                  onClick={() => setLayoutMode("horizontal")}
                  className={`px-3 py-1.5 rounded-md text-sm font-medium flex items-center gap-1.5 ${
                    layoutMode === "horizontal"
                      ? "bg-white dark:bg-gray-800 text-gray-900 dark:text-white shadow"
                      : "text-gray-600 dark:text-gray-400"
                  }`}
                  title="Disposition horizontale"
                >
                  <i className="fas fa-columns"></i>
                  <span className="hidden sm:inline">Horizontal</span>
                </button>
                <button
                  onClick={() => setLayoutMode("vertical")}
                  className={`px-3 py-1.5 rounded-md text-sm font-medium flex items-center gap-1.5 ${
                    layoutMode === "vertical"
                      ? "bg-white dark:bg-gray-800 text-gray-900 dark:text-white shadow"
                      : "text-gray-600 dark:text-gray-400"
                  }`}
                  title="Disposition verticale"
                >
                  <i className="fas fa-grip-lines"></i>
                  <span className="hidden sm:inline">Vertical</span>
                </button>
                <button
                  onClick={() => setLayoutMode(layoutMode === "focus" ? "horizontal" : "focus")}
                  className={`px-3 py-1.5 rounded-md text-sm font-medium flex items-center gap-1.5 ${
                    layoutMode === "focus"
                      ? "bg-white dark:bg-gray-800 text-gray-900 dark:text-white shadow"
                      : "text-gray-600 dark:text-gray-400"
                  }`}
                  title={layoutMode === "focus" ? "Afficher le média" : "Mode focus (masquer le média)"}
                >
                  <i className={`fas ${layoutMode === "focus" ? "fa-columns" : "fa-eye-slash"}`}></i>
                  <span className="hidden sm:inline">{layoutMode === "focus" ? "Afficher" : "Focus"}</span>
                </button>
              </div>
              
              <button
                onClick={() => setSelectedDocument(null)}
                className="px-4 py-2 bg-gray-200 hover:bg-gray-300 dark:bg-gray-700 dark:hover:bg-gray-600 text-gray-800 dark:text-gray-200 rounded-md flex items-center gap-2 transition-colors"
              >
                <i className="fas fa-arrow-left"></i>
                Changer de document
              </button>
            </div>
          </div>
          
          {/* Zone de transcription avec layout ajustable */}
          <div 
            className={`flex ${layoutMode === "horizontal" ? "flex-row" : layoutMode === "focus" ? "flex-col" : "flex-col"}`}
            style={{ height: "calc(100vh - 300px)" }}
          >
            {/* Panneau média (audio/PDF/image) - caché en mode focus */}
            {layoutMode !== "focus" && (
              <div
                className="flex-1 min-w-0 min-h-0 bg-gray-50 dark:bg-gray-700/50 border-r border-b border-gray-200 dark:border-gray-700 relative overflow-hidden"
                style={{ flex: `${splitRatio * 100}%` }}
              >
                {mediaType === "audio" ? (
                  <div className="h-full p-4">
                    <AudioPlayer 
                      audioUrl={selectedDocument.file_url!} 
                    />
                  </div>
                ) : mediaType === "pdf" ? (
                  <PDFViewer fileUrl={selectedDocument.file_url!} />
                ) : mediaType === "image" ? (
                  <div className="h-full flex flex-col items-center justify-center p-6 text-center">
                    <div className="w-16 h-16 bg-green-100 dark:bg-green-900/30 rounded-full flex items-center justify-center mb-4">
                      <i className="fas fa-image text-green-600 dark:text-green-400 text-3xl"></i>
                    </div>
                    <h3 className="text-lg font-medium text-gray-800 dark:text-white mb-2">
                      Visualiseur d'image
                    </h3>
                    <p className="text-gray-600 dark:text-gray-400 mb-4">
                      {selectedDocument.file_url?.split("/").pop()}
                    </p>
                    {selectedDocument.file_url && (
                      <img 
                        src={selectedDocument.file_url} 
                        alt="Aperçu" 
                        className="max-w-full max-h-64 object-contain rounded-lg shadow-md"
                      />
                    )}
                  </div>
                ) : (
                  <div className="h-full flex flex-col items-center justify-center p-6 text-center text-gray-500 dark:text-gray-400">
                    <i className="fas fa-exclamation-triangle text-4xl mb-3"></i>
                    <p>Type de fichier non supporté pour la transcription</p>
                    <p className="text-sm mt-1">Formats supportés : MP3, WAV, PDF, JPG, PNG</p>
                  </div>
                )}
                
                {/* Poignée de redimensionnement */}
                <div
                  className={`absolute ${
                    layoutMode === "horizontal" 
                      ? "top-0 bottom-0 right-0 w-3 cursor-col-resize" 
                      : "left-0 right-0 bottom-0 h-3 cursor-row-resize"
                  } bg-gray-300 dark:bg-gray-600 hover:bg-gray-400 dark:hover:bg-gray-500 transition-colors`}
                  onMouseDown={(e) => {
                    e.preventDefault();
                    const start = layoutMode === "horizontal" ? e.clientX : e.clientY;
                    const container = e.currentTarget.parentElement;
                    if (!container) return;
                    
                    const rect = container.getBoundingClientRect();
                    const startRatio = splitRatio;
                    
                    const handleMouseMove = (moveEvent: MouseEvent) => {
                      const delta = layoutMode === "horizontal" 
                        ? (moveEvent.clientX - start) / rect.width
                        : (moveEvent.clientY - start) / rect.height;
                      
                      let newRatio = Math.min(0.8, Math.max(0.2, startRatio + delta));
                      setSplitRatio(newRatio);
                    };
                    
                    const handleMouseUp = () => {
                      document.removeEventListener("mousemove", handleMouseMove);
                      document.removeEventListener("mouseup", handleMouseUp);
                    };
                    
                    document.addEventListener("mousemove", handleMouseMove);
                    document.addEventListener("mouseup", handleMouseUp);
                  }}
                />
              </div>
            )}
            
            {/* Panneau éditeur de transcription */}
            <div 
              className="flex-1 min-w-0 min-h-0 bg-white dark:bg-gray-800 p-6 overflow-auto"
              style={{ flex: layoutMode === "focus" ? "1" : `${(1 - splitRatio) * 100}%` }}
            >
              <TranscriptionEditor
                content={transcriptionContent}
                onChange={setTranscriptionContent}
                placeholder={activeSubTab === 'launch' 
                  ? "Commencez la transcription ici..." 
                  : activeSubTab === 'review'
                  ? "Relisez et corrigez la transcription..."
                  : "Ajoutez des tags et métadonnées..."}
              />
              
              <div className="flex flex-col sm:flex-row sm:justify-end gap-3 pt-4 border-t border-gray-200 dark:border-gray-700">
                <button
                  onClick={() => setSelectedDocument(null)}
                  className="px-4 py-2.5 text-sm font-medium text-gray-700 dark:text-gray-300 bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 rounded-lg transition-colors"
                >
                  Annuler
                </button>
                <button
                  onClick={handleSave}
                  className={`px-4 py-2.5 text-sm font-medium text-white rounded-lg transition-colors flex items-center justify-center ${
                    activeSubTab === 'launch'
                      ? 'bg-green-600 hover:bg-green-700'
                      : activeSubTab === 'review'
                      ? 'bg-yellow-600 hover:bg-yellow-700'
                      : 'bg-purple-600 hover:bg-purple-700'
                  }`}
                >
                  {activeSubTab === 'launch' && <><i className="fas fa-save mr-2"></i>Sauvegarder et passer à la relecture</>}
                  {activeSubTab === 'review' && <><i className="fas fa-check mr-2"></i>Valider la relecture</>}
                  {activeSubTab === 'tagging' && <><i className="fas fa-tags mr-2"></i>Finaliser le tagging</>}
                </button>
              </div>
            </div>
          </div>
          
          {/* Barre d'état */}
          <div className="border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-700/50 px-6 py-3 text-sm">
            <div className="flex flex-wrap justify-between items-center gap-4">
              {/* Statistiques */}
              <div className="flex items-center gap-6 text-gray-600 dark:text-gray-400">
                <span className="flex items-center gap-1.5">
                  <i className="fas fa-font"></i>
                  <span>{transcriptionContent.split(/\s+/).filter(w => w.length > 0).length} mots</span>
                </span>
                <span className="flex items-center gap-1.5">
                  <i className="fas fa-text-height"></i>
                  <span>{transcriptionContent.length} caractères</span>
                </span>
                <span className="flex items-center gap-1.5">
                  <i className="fas fa-clock"></i>
                  <span>Temps : {formatTimeSpent()}</span>
                </span>
              </div>
              
              {/* Sauvegarde auto */}
              <div className="flex items-center gap-2 text-gray-500 dark:text-gray-400">
                <i className={`fas fa-save ${lastSaveTime ? 'text-green-500' : 'text-gray-400'}`}></i>
                <span>
                  {lastSaveTime 
                    ? `Dernière sauvegarde : il y a ${getTimeAgo(lastSaveTime)}`
                    : 'Brouillon non sauvegardé'}
                </span>
              </div>
              
              {/* Raccourcis */}
              <div className="hidden md:flex items-center gap-3 text-gray-400">
                <span className="flex items-center gap-1">
                  <kbd className="px-2 py-1 bg-gray-200 dark:bg-gray-600 rounded text-xs">Ctrl+S</kbd>
                  <span className="text-xs">Sauvegarder</span>
                </span>
                <span className="flex items-center gap-1">
                  <kbd className="px-2 py-1 bg-gray-200 dark:bg-gray-600 rounded text-xs">Espace</kbd>
                  <span className="text-xs">Play/Pause</span>
                </span>
                <span className="flex items-center gap-1">
                  <kbd className="px-2 py-1 bg-gray-200 dark:bg-gray-600 rounded text-xs">Ctrl+←</kbd>
                  <span className="text-xs">Précédent</span>
                </span>
                <span className="flex items-center gap-1">
                  <kbd className="px-2 py-1 bg-gray-200 dark:bg-gray-600 rounded text-xs">Ctrl+→</kbd>
                  <span className="text-xs">Suivant</span>
                </span>
              </div>
            </div>
          </div>
        </div>
      )}
      
      {/* Aperçu document suivant (en bas à droite) */}
      {selectedDocument && filteredDocuments.length > 1 && (
        <div className="fixed bottom-4 right-4 bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg shadow-lg p-3 max-w-xs z-40 animate-fade-in">
          <div className="flex items-start gap-3">
            <div className="flex-shrink-0">
              <div className="w-10 h-10 bg-blue-100 dark:bg-blue-900/30 rounded-full flex items-center justify-center">
                <i className="fas fa-arrow-right text-blue-600 dark:text-blue-400"></i>
              </div>
            </div>
            <div className="flex-1 min-w-0">
              <p className="text-xs font-medium text-gray-500 dark:text-gray-400 mb-1">Prochain document</p>
              <h4 className="text-sm font-semibold text-gray-900 dark:text-white line-clamp-2">
                {getNextDocument()?.title || 'Aucun document suivant'}
              </h4>
              <div className="mt-2 flex items-center justify-between">
                <span className="text-xs text-gray-500 dark:text-gray-400">
                  {getNextDocument()?.type}
                </span>
                <button
                  onClick={() => {
                    const next = getNextDocument();
                    if (next) {
                      setSelectedDocument(next);
                      setStartTime(new Date());
                    }
                  }}
                  className="px-2.5 py-1 text-xs bg-blue-600 hover:bg-blue-700 text-white rounded-md transition-colors"
                >
                  Passer maintenant
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Transcription;
